__global__
__launch_bounds__(128) void fused_matmul(float* A, float* B, float* C, int M, int N, int K) {
    int row_base = (blockIdx.y * blockDim.y + threadIdx.y) * 8;
    int col_base = (blockIdx.x * blockDim.x + threadIdx.x) * 4;
    __shared__ float As[2080];
    int sr0 = threadIdx.y * 8;
    int sr1 = sr0 + 1;
    int sr2 = sr0 + 2;
    int sr3 = sr0 + 3;
    int sr4 = sr0 + 4;
    int sr5 = sr0 + 5;
    int sr6 = sr0 + 6;
    int sr7 = sr0 + 7;
    float acc00 = 0.0f;
    float acc01 = 0.0f;
    float acc02 = 0.0f;
    float acc03 = 0.0f;
    float acc10 = 0.0f;
    float acc11 = 0.0f;
    float acc12 = 0.0f;
    float acc13 = 0.0f;
    float acc20 = 0.0f;
    float acc21 = 0.0f;
    float acc22 = 0.0f;
    float acc23 = 0.0f;
    float acc30 = 0.0f;
    float acc31 = 0.0f;
    float acc32 = 0.0f;
    float acc33 = 0.0f;
    float acc40 = 0.0f;
    float acc41 = 0.0f;
    float acc42 = 0.0f;
    float acc43 = 0.0f;
    float acc50 = 0.0f;
    float acc51 = 0.0f;
    float acc52 = 0.0f;
    float acc53 = 0.0f;
    float acc60 = 0.0f;
    float acc61 = 0.0f;
    float acc62 = 0.0f;
    float acc63 = 0.0f;
    float acc70 = 0.0f;
    float acc71 = 0.0f;
    float acc72 = 0.0f;
    float acc73 = 0.0f;
    for (int tile_k = 0; tile_k < K; tile_k += 64) {
        for (int a_s = threadIdx.x; a_s < 64; a_s += 32) {
            As[sr0 * 65 + a_s] = A[(row_base + 0) * K + (tile_k + a_s)];
            As[sr1 * 65 + a_s] = A[(row_base + 1) * K + (tile_k + a_s)];
            As[sr2 * 65 + a_s] = A[(row_base + 2) * K + (tile_k + a_s)];
            As[sr3 * 65 + a_s] = A[(row_base + 3) * K + (tile_k + a_s)];
            As[sr4 * 65 + a_s] = A[(row_base + 4) * K + (tile_k + a_s)];
            As[sr5 * 65 + a_s] = A[(row_base + 5) * K + (tile_k + a_s)];
            As[sr6 * 65 + a_s] = A[(row_base + 6) * K + (tile_k + a_s)];
            As[sr7 * 65 + a_s] = A[(row_base + 7) * K + (tile_k + a_s)];
        }
        __syncthreads();
        #pragma unroll
        for (int kk = 0; kk < 64; kk++) {
            float a0 = As[sr0 * 65 + kk];
            float a1 = As[sr1 * 65 + kk];
            float a2 = As[sr2 * 65 + kk];
            float a3 = As[sr3 * 65 + kk];
            float a4 = As[sr4 * 65 + kk];
            float a5 = As[sr5 * 65 + kk];
            float a6 = As[sr6 * 65 + kk];
            float a7 = As[sr7 * 65 + kk];
            float4 b4 = *reinterpret_cast<float4*>(&B[(tile_k + kk) * N + col_base]);
            acc00 += a0 * b4.x;
            acc01 += a0 * b4.y;
            acc02 += a0 * b4.z;
            acc03 += a0 * b4.w;
            acc10 += a1 * b4.x;
            acc11 += a1 * b4.y;
            acc12 += a1 * b4.z;
            acc13 += a1 * b4.w;
            acc20 += a2 * b4.x;
            acc21 += a2 * b4.y;
            acc22 += a2 * b4.z;
            acc23 += a2 * b4.w;
            acc30 += a3 * b4.x;
            acc31 += a3 * b4.y;
            acc32 += a3 * b4.z;
            acc33 += a3 * b4.w;
            acc40 += a4 * b4.x;
            acc41 += a4 * b4.y;
            acc42 += a4 * b4.z;
            acc43 += a4 * b4.w;
            acc50 += a5 * b4.x;
            acc51 += a5 * b4.y;
            acc52 += a5 * b4.z;
            acc53 += a5 * b4.w;
            acc60 += a6 * b4.x;
            acc61 += a6 * b4.y;
            acc62 += a6 * b4.z;
            acc63 += a6 * b4.w;
            acc70 += a7 * b4.x;
            acc71 += a7 * b4.y;
            acc72 += a7 * b4.z;
            acc73 += a7 * b4.w;
        }
        __syncthreads();
    }
    C[(row_base + 0) * N + (col_base + 0)] = acc00;
    C[(row_base + 0) * N + (col_base + 1)] = acc01;
    C[(row_base + 0) * N + (col_base + 2)] = acc02;
    C[(row_base + 0) * N + (col_base + 3)] = acc03;
    C[(row_base + 1) * N + (col_base + 0)] = acc10;
    C[(row_base + 1) * N + (col_base + 1)] = acc11;
    C[(row_base + 1) * N + (col_base + 2)] = acc12;
    C[(row_base + 1) * N + (col_base + 3)] = acc13;
    C[(row_base + 2) * N + (col_base + 0)] = acc20;
    C[(row_base + 2) * N + (col_base + 1)] = acc21;
    C[(row_base + 2) * N + (col_base + 2)] = acc22;
    C[(row_base + 2) * N + (col_base + 3)] = acc23;
    C[(row_base + 3) * N + (col_base + 0)] = acc30;
    C[(row_base + 3) * N + (col_base + 1)] = acc31;
    C[(row_base + 3) * N + (col_base + 2)] = acc32;
    C[(row_base + 3) * N + (col_base + 3)] = acc33;
    C[(row_base + 4) * N + (col_base + 0)] = acc40;
    C[(row_base + 4) * N + (col_base + 1)] = acc41;
    C[(row_base + 4) * N + (col_base + 2)] = acc42;
    C[(row_base + 4) * N + (col_base + 3)] = acc43;
    C[(row_base + 5) * N + (col_base + 0)] = acc50;
    C[(row_base + 5) * N + (col_base + 1)] = acc51;
    C[(row_base + 5) * N + (col_base + 2)] = acc52;
    C[(row_base + 5) * N + (col_base + 3)] = acc53;
    C[(row_base + 6) * N + (col_base + 0)] = acc60;
    C[(row_base + 6) * N + (col_base + 1)] = acc61;
    C[(row_base + 6) * N + (col_base + 2)] = acc62;
    C[(row_base + 6) * N + (col_base + 3)] = acc63;
    C[(row_base + 7) * N + (col_base + 0)] = acc70;
    C[(row_base + 7) * N + (col_base + 1)] = acc71;
    C[(row_base + 7) * N + (col_base + 2)] = acc72;
    C[(row_base + 7) * N + (col_base + 3)] = acc73;
}
